import fs from 'fs';
import path from 'path';

/**
 * MAKE MIGRATION IDEMPOTENT
 *
 * Transforms a Supabase migration file (generated by `supabase migration squash`)
 * so it can be safely re-applied on a database that already has some or all objects.
 *
 * Transformations:
 *   1. ADD CONSTRAINT   → wrapped in DO $$ IF NOT EXISTS (pg_constraint) ... END $$
 *   2. CREATE POLICY     → prepended with DROP POLICY IF EXISTS
 *   3. CREATE INDEX      → CREATE INDEX IF NOT EXISTS
 *   4. CREATE UNIQUE INDEX → CREATE UNIQUE INDEX IF NOT EXISTS
 *
 * Usage:
 *   node scripts/make-migration-idempotent.mjs [path]
 *
 *   path  Optional. Defaults to the single .sql file in supabase/migrations/.
 *         If multiple files exist, you must specify which one to transform.
 */

const MIGRATIONS_DIR = path.resolve('supabase/migrations');

// ---------------------------------------------------------------------------
// Resolve target file
// ---------------------------------------------------------------------------

function resolveTarget() {
  const explicit = process.argv[2];
  if (explicit) {
    const resolved = path.resolve(explicit);
    if (!fs.existsSync(resolved)) {
      console.error(`File not found: ${resolved}`);
      process.exit(1);
    }
    return resolved;
  }

  const files = fs.readdirSync(MIGRATIONS_DIR).filter((f) => f.endsWith('.sql'));

  if (files.length === 0) {
    console.error('No .sql files found in supabase/migrations/');
    process.exit(1);
  }
  if (files.length > 1) {
    console.error(
      'Multiple migration files found. Specify which one to transform:\n' +
        files
          .map((f) => `  node scripts/make-migration-idempotent.mjs supabase/migrations/${f}`)
          .join('\n')
    );
    process.exit(1);
  }

  return path.join(MIGRATIONS_DIR, files[0]);
}

// ---------------------------------------------------------------------------
// Transformation helpers
// ---------------------------------------------------------------------------

/**
 * Wrap `ALTER TABLE ONLY ... ADD CONSTRAINT "name" ...;`
 * (possibly spanning two lines) in a DO $$ IF NOT EXISTS block.
 */
function wrapConstraints(content) {
  let count = 0;

  // Match only top-level (non-indented) ALTER TABLE ONLY ... ADD CONSTRAINT
  const re = /^(ALTER TABLE ONLY [^\n]+\n\s+ADD CONSTRAINT "([^"]+)"[^;]+;)/gm;

  content = content.replace(re, (_match, full, conname) => {
    count++;
    const indented = full.replace(/\n\s+/g, '\n        ');
    return [
      `DO $$ BEGIN`,
      `  IF NOT EXISTS (SELECT 1 FROM pg_constraint WHERE conname = '${conname}') THEN`,
      `    ${indented}`,
      `  END IF;`,
      `END $$;`,
    ].join('\n');
  });

  return { content, count };
}

/**
 * Prepend DROP POLICY IF EXISTS before each CREATE POLICY.
 */
function addDropPolicies(content) {
  let count = 0;

  // Match CREATE POLICY "name" ON "schema"."table"
  const re = /CREATE POLICY "([^"]+)" ON ("(?:[^"]+)"\.?"(?:[^"]+)")/g;

  // Collect matches first to avoid issues with overlapping replacements
  const replacements = [];
  let m;
  while ((m = re.exec(content)) !== null) {
    // Check preceding text for DROP POLICY IF EXISTS on the same line area
    const before = content.substring(Math.max(0, m.index - 200), m.index);
    if (before.includes(`DROP POLICY IF EXISTS "${m[1]}"`)) continue;

    replacements.push({
      index: m.index,
      policyName: m[1],
      tableRef: m[2],
    });
  }

  // Apply in reverse order to preserve indices
  for (let i = replacements.length - 1; i >= 0; i--) {
    const { index, policyName, tableRef } = replacements[i];
    const dropLine = `DROP POLICY IF EXISTS "${policyName}" ON ${tableRef};\n`;
    content = content.substring(0, index) + dropLine + content.substring(index);
    count++;
  }

  return { content, count };
}

/**
 * CREATE INDEX → CREATE INDEX IF NOT EXISTS
 * CREATE UNIQUE INDEX → CREATE UNIQUE INDEX IF NOT EXISTS
 */
function addIndexIfNotExists(content) {
  let count = 0;

  content = content.replace(/CREATE (UNIQUE )?INDEX (?!IF NOT EXISTS)/g, (_match, unique) => {
    count++;
    return `CREATE ${unique || ''}INDEX IF NOT EXISTS `;
  });

  return { content, count };
}

// ---------------------------------------------------------------------------
// Main
// ---------------------------------------------------------------------------

const filePath = resolveTarget();
console.log(`Transforming: ${filePath}\n`);

let content = fs.readFileSync(filePath, 'utf-8');

const r1 = wrapConstraints(content);
content = r1.content;

const r2 = addDropPolicies(content);
content = r2.content;

const r3 = addIndexIfNotExists(content);
content = r3.content;

fs.writeFileSync(filePath, content, 'utf-8');

console.log(`  ADD CONSTRAINT  → IF NOT EXISTS wrappers:  ${r1.count}`);
console.log(`  CREATE POLICY   → DROP IF EXISTS prepended: ${r2.count}`);
console.log(`  CREATE INDEX    → IF NOT EXISTS added:      ${r3.count}`);
console.log(`\nDone. File updated in-place.`);
